async (params, browser) => {
  // Open Figma file
  await browser.open(`${params.file_url}`)

  // Wait for editor to load
  await browser.waitForSelector('[class*="toolbar"], [data-testid="canvas"]', 20000)

  // Let editor initialize
  await browser.wait(3000)

  // Open comments panel
  await browser.click('[class*="comment"] button, [data-testid="comments-toggle"], button[aria-label*="Comment"], [class*="toolbar"] [class*="comment_icon"]')

  // Let comments panel load
  await browser.wait(2000)

  // Click comment input area
  await browser.click('[data-testid="comment-input"], textarea.comment-input, [class*="comment_input"], [class*="comment"] textarea, [class*="new_comment"] [contenteditable], [class*="comment_composer"] [contenteditable]')

  // Let input focus
  await browser.wait(500)

  // Type comment text
  const type_result = await browser.evaluate(`const input = document.querySelector('[data-testid="comment-input"], textarea.comment-input, [class*="comment_input"], [class*="comment"] textarea, [class*="new_comment"] [contenteditable], [class*="comment_composer"] [contenteditable]'); if (!input) throw new Error('Comment input not found'); input.focus(); if (input.tagName === 'TEXTAREA') { const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set; nativeSetter.call(input, params.comment); input.dispatchEvent(new Event('input', { bubbles: true })); input.dispatchEvent(new Event('change', { bubbles: true })); } else if (input.tagName === 'INPUT') { const nativeSetter = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set; nativeSetter.call(input, params.comment); input.dispatchEvent(new Event('input', { bubbles: true })); input.dispatchEvent(new Event('change', { bubbles: true })); } else { input.textContent = params.comment; input.dispatchEvent(new Event('input', { bubbles: true })); } return { typed: true }`)

  // Let input register
  await browser.wait(500)

  // Submit comment
  const result = await browser.evaluate(`const submitBtn = document.querySelector('[class*="comment"] button[type="submit"], [data-testid="comment-submit"], [class*="comment_submit"], [class*="comment_composer"] button[class*="submit"], [class*="comment"] [class*="send"]'); if (submitBtn) { submitBtn.click(); } else { const input = document.querySelector('[data-testid="comment-input"], textarea.comment-input, [class*="comment_input"], [class*="comment"] textarea, [class*="comment_composer"] [contenteditable]'); if (input) { input.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, ctrlKey: true, bubbles: true })); } } return { success: true, comment: params.comment, file_url: window.location.href }`)

  return result
}
